// MapComponent.js
import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, useMap } from "react-leaflet";
import "leaflet/dist/leaflet.css";

// Component to add zoom buttons on left
const ZoomControlLeft = () => {
  const map = useMap();
  return (
    <div style={{ position: "absolute", top: 10, left: 10, zIndex: 1000 }}>
      <button onClick={() => map.zoomIn()} style={{ display: "block", marginBottom: 5 }}>+</button>
      <button onClick={() => map.zoomOut()} style={{ display: "block" }}>-</button>
    </div>
  );
};

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  const fetchBuses = async () => {
    try {
      const res = await fetch("http://localhost:8000/buses");
      const data = await res.json();
      setBuses(data);
    } catch (err) {
      console.error("Error fetching buses:", err);
    }
  };

  useEffect(() => {
    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // every 2 mins
    return () => clearInterval(interval);
  }, []);

  const normalCount = buses.filter(b => b.status === "normal").length;
  const ghostCount = buses.filter(b => b.status === "ghost").length;
  const anomalyCount = buses.filter(b => b.status === "anomaly").length;

  return (
    <div style={{ width: "100vw", height: "100vh", position: "relative" }}>
      <MapContainer center={[40.7128, -74.0060]} zoom={11} style={{ width: "100%", height: "100%" }}>
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />
        {buses.map(bus => (
          <CircleMarker
            key={`${bus.id}_${bus.timestamp}`}
            center={[bus.lat, bus.lon]}
            radius={8}
            color={bus.status === "ghost" ? "red" : bus.status === "anomaly" ? "orange" : "green"}
            fillOpacity={0.8}
          />
        ))}
        <ZoomControlLeft />
      </MapContainer>

      {/* Bus counts */}
      <div style={{
        position: "absolute",
        bottom: 10,
        left: 10,
        backgroundColor: "white",
        padding: "10px",
        borderRadius: "8px",
        fontWeight: "bold",
        zIndex: 1000
      }}>
        Normal: {normalCount} | Ghost: {ghostCount} | Anomaly: {anomalyCount}
      </div>

      {/* Toggle chart button */}
      <button
        style={{ position: "absolute", top: 10, left: 70, zIndex: 1000 }}
        onClick={() => setShowChart(!showChart)}
      >
        {showChart ? "Hide Chart" : "Show Chart"}
      </button>

      {showChart && (
        <div style={{ position: "absolute", bottom: 50, left: 10, zIndex: 1000, backgroundColor: "white", padding: 10, borderRadius: 8 }}>
          {/* Here you can render your BusTrendChart component if you have it */}
          <div>Chart placeholder</div>
        </div>
      )}
    </div>
  );
};

export default MapComponent;
